import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './CreateCampaign.css';

const CATEGORIES = [
  'Medical', 'Education', 'Social', 'Environment',
  'Animal Welfare', 'Disaster Relief', 'Other'
];

const CATEGORY_EMOJI = {
  Medical: '🏥', Education: '📚', Social: '🤝',
  Environment: '🌿', 'Animal Welfare': '🐾',
  'Disaster Relief': '⛑️', Other: '💡'
};

const TIPS = [
  'Be specific about how funds will be used',
  'Add a real photo to build donor trust',
  'Share a personal story to connect emotionally',
  'Set a realistic goal based on actual needs',
  'Update donors with progress milestones',
];

const CreateCampaign = () => {
  const [formData, setFormData] = useState({
    title: '', description: '', goal: '', category: '', imageUrl: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [imageError, setImageError] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
    setError('');
    if (e.target.name === 'imageUrl') setImageError(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const { title, description, goal, category } = formData;

    if (!title.trim() || !description.trim() || !goal || !category) {
      setError('Title, description, goal, and category are all required.'); return;
    }
    if (title.trim().length < 5) {
      setError('Campaign title must be at least 5 characters.'); return;
    }
    if (description.trim().length < 20) {
      setError('Description must be at least 20 characters to help donors understand your cause.'); return;
    }
    const parsedGoal = Number(goal);
    if (isNaN(parsedGoal) || parsedGoal < 100) {
      setError('Fundraising goal must be at least ₹100.'); return;
    }

    try {
      setLoading(true);
      setError('');
      const { data } = await axios.post('/api/campaigns', {
        title: formData.title.trim(),
        description: formData.description.trim(),
        goal: parsedGoal,
        category,
        imageUrl: formData.imageUrl.trim()
      });
      navigate(`/campaigns/${data.campaign._id}`);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create campaign. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const goalNum = Number(formData.goal);
  const estimatedDonors = goalNum > 0 ? Math.ceil(goalNum / 500) : 0;
  const previewEmoji = CATEGORY_EMOJI[formData.category] || '💡';

  return (
    <div className="create-campaign-page">
      <div className="container">

        {/* Page Header */}
        <div className="create-page-header">
          <h1>🚀 Start a Campaign</h1>
          <p>Share your cause with millions of compassionate donors across India.</p>
        </div>

        <div className="create-layout">

          {/* ── Form ───────────────────────────────────────── */}
          <div className="create-form-card" id="create-campaign-container">

            {error && (
              <div className="alert alert-error" id="create-error-alert" role="alert">
                <span>⚠️</span>
                <p>{error}</p>
              </div>
            )}

            <form onSubmit={handleSubmit} noValidate id="create-campaign-form">

              {/* Section — About */}
              <div className="form-section-title">📋 Campaign Details</div>

              <div className="form-group">
                <label className="form-label" htmlFor="campaign-title">
                  Campaign Title *
                </label>
                <input
                  id="campaign-title"
                  name="title"
                  type="text"
                  className="form-input"
                  placeholder="e.g., Help Sita get life-saving cancer treatment"
                  value={formData.title}
                  onChange={handleChange}
                  maxLength={100}
                  required
                />
                <span className="char-count">{formData.title.length}/100</span>
              </div>

              <div className="form-group">
                <label className="form-label" htmlFor="campaign-description">
                  Campaign Story *
                </label>
                <textarea
                  id="campaign-description"
                  name="description"
                  className="form-input"
                  placeholder="Tell your story — who needs help, why, and exactly how the funds will be used. Be honest and specific to build donor trust..."
                  value={formData.description}
                  onChange={handleChange}
                  rows={7}
                  required
                />
                <span className="char-count">{formData.description.length} characters (min 20)</span>
              </div>

              {/* Section — Goal & Category */}
              <div className="form-section-title" style={{ marginTop: '1.5rem' }}>
                🎯 Goal & Category
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label className="form-label" htmlFor="campaign-goal">
                    Fundraising Goal (₹) *
                  </label>
                  <input
                    id="campaign-goal"
                    name="goal"
                    type="number"
                    className="form-input"
                    placeholder="e.g., 500000"
                    value={formData.goal}
                    onChange={handleChange}
                    min={100}
                    required
                  />
                </div>

                <div className="form-group">
                  <label className="form-label" htmlFor="campaign-category">
                    Category *
                  </label>
                  <select
                    id="campaign-category"
                    name="category"
                    className="form-input"
                    value={formData.category}
                    onChange={handleChange}
                    required
                  >
                    <option value="" disabled>Select category...</option>
                    {CATEGORIES.map((cat) => (
                      <option key={cat} value={cat}>
                        {CATEGORY_EMOJI[cat]} {cat}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              {/* Section — Image */}
              <div className="form-section-title" style={{ marginTop: '1.5rem' }}>
                🖼️ Campaign Image (Optional)
              </div>

              <div className="form-group">
                <label className="form-label" htmlFor="campaign-image">
                  Image URL
                </label>
                <input
                  id="campaign-image"
                  name="imageUrl"
                  type="url"
                  className="form-input"
                  placeholder="https://example.com/your-image.jpg"
                  value={formData.imageUrl}
                  onChange={handleChange}
                />
                <span className="char-count">
                  Paste a direct link to an image that represents your cause
                </span>

                {formData.imageUrl && !imageError && (
                  <div className="image-preview-box" id="image-preview">
                    <img
                      src={formData.imageUrl}
                      alt="Campaign preview"
                      onError={() => setImageError(true)}
                    />
                    <span className="image-preview-label">Preview</span>
                  </div>
                )}
                {formData.imageUrl && imageError && (
                  <div className="alert alert-error" style={{ marginTop: '0.5rem', marginBottom: 0 }}>
                    <span>⚠️</span>
                    <p>Image URL could not be loaded. Please check the URL.</p>
                  </div>
                )}
              </div>

              {/* Submit */}
              <button
                type="submit"
                className="create-submit-btn"
                disabled={loading}
                id="btn-create-submit"
                style={{ marginTop: '1.5rem' }}
              >
                {loading ? (
                  <><span className="spinner" /> Creating Campaign...</>
                ) : (
                  '🚀 Launch My Campaign'
                )}
              </button>
            </form>
          </div>

          {/* ── Sidebar ─────────────────────────────────────── */}
          <div className="create-sidebar">

            {/* Live Preview */}
            <div className="preview-card" id="campaign-preview">
              <div className="preview-card-header">
                👁️ Live Preview
              </div>
              <div className="preview-card-body">
                <div className="preview-image-box">
                  {formData.imageUrl && !imageError ? (
                    <img
                      src={formData.imageUrl}
                      alt="preview"
                      onError={() => setImageError(true)}
                    />
                  ) : (
                    <span>{previewEmoji}</span>
                  )}
                </div>

                {formData.category && (
                  <span className="badge badge-blue" style={{ marginBottom: '0.6rem', display: 'inline-flex' }}>
                    {CATEGORY_EMOJI[formData.category]} {formData.category}
                  </span>
                )}

                <p className="preview-title">
                  {formData.title || 'Your campaign title will appear here...'}
                </p>

                <p className="preview-desc">
                  {formData.description
                    ? formData.description.substring(0, 120) + (formData.description.length > 120 ? '...' : '')
                    : 'Your campaign story will appear here. Make it compelling!'}
                </p>

                {goalNum > 0 && (
                  <>
                    <div className="progress-bar-wrapper">
                      <div className="progress-bar-fill" style={{ width: '0%' }} />
                    </div>
                    <div className="preview-progress-label">
                      <span style={{ color: 'var(--green)', fontWeight: 600 }}>₹0 raised</span>
                      <span>Goal: ₹{goalNum.toLocaleString('en-IN')}</span>
                    </div>

                    {estimatedDonors > 0 && (
                      <div className="preview-goal-hint">
                        💡 At avg. ₹500/donor, you need approx.{' '}
                        <strong>{estimatedDonors.toLocaleString('en-IN')} donors</strong> to reach your goal.
                      </div>
                    )}
                  </>
                )}
              </div>
            </div>

            {/* Tips */}
            <div className="tips-card" id="campaign-tips">
              <p className="tips-title">✅ Tips for a Successful Campaign</p>
              <ul className="tips-list">
                {TIPS.map((tip, i) => (
                  <li key={i}>{tip}</li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CreateCampaign;
